import{_ as e,o,c as l,a2 as t}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Nastavení nahrávání","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/index.md","filePath":"cs-CZ/upload/index.md","lastUpdated":1781962217000}'),i={name:"cs-CZ/upload/index.md"};function n(r,a,d,s,p,c){return o(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="nastaveni-nahravani" tabindex="-1">Nastavení nahrávání <a class="header-anchor" href="#nastaveni-nahravani" aria-label="Permalink to &quot;Nastavení nahrávání&quot;">​</a></h1><p>Tato část používá stejné pořadí kanálů jako stránka Nastavení systému, takže můžete rovnou přejít k poskytovateli úložiště, který právě nastavujete.</p><h2 id="jak-je-tato-cast-usporadana" tabindex="-1">Jak je tato část uspořádána <a class="header-anchor" href="#jak-je-tato-cast-usporadana" aria-label="Permalink to &quot;Jak je tato část uspořádána&quot;">​</a></h2><ul><li>Každý poskytovatel má vlastní stránku. Oddělení 13 nahrávacích kanálů usnadňuje sledování postupu.</li><li>Snímky obrazovky jsou v <code>../../image/upload/provider-name/</code> a jednotlivé stránky na ně odkazují lokálně.</li><li>Technické názvy a názvy polí zůstávají co nejblíže rozhraní produktu, zejména <code>Endpoint</code>, <code>Client ID</code>, <code>Access Token</code> a <code>Refresh Token</code>.</li></ul><h2 id="prehled-kanalu" tabindex="-1">Přehled kanálů <a class="header-anchor" href="#prehled-kanalu" aria-label="Permalink to &quot;Přehled kanálů&quot;">​</a></h2><ul><li><a href="./telegram">Telegram</a></li><li><a href="./cloudflare-r2">Cloudflare R2</a></li><li><a href="./s3">S3</a></li><li><a href="./webdav">WebDAV</a></li><li><a href="./discord">Discord</a></li><li><a href="./huggingface">Hugging Face</a></li><li><a href="./github-releases">GitHub Releases</a></li><li><a href="./gitlab-packages">GitLab Packages</a></li><li><a href="./onedrive">OneDrive</a></li><li><a href="./google-drive">Google Drive</a></li><li><a href="./dropbox">Dropbox</a></li><li><a href="./yandex">Yandex</a></li><li><a href="./pcloud">pCloud</a></li></ul><h2 id="co-tato-kapitola-resi" tabindex="-1">Co tato kapitola řeší <a class="header-anchor" href="#co-tato-kapitola-resi" aria-label="Permalink to &quot;Co tato kapitola řeší&quot;">​</a></h2><ul><li>Jak přidat jednotlivé nahrávací kanály.</li><li>Jaké přihlašovací údaje, ID nebo oprávnění si připravit předem.</li><li>Jak ověřit, že je kanál připravený pro nahrávání souborů.</li></ul><p>Podrobnosti k řešení problémů, limitům kapacity a doporučeným postupům jsou uvedené u konkrétních služeb.</p>',9)])])}const k=e(i,[["render",n]]);export{h as __pageData,k as default};
